mapper.select:
SELECT FIN.BUYER_CD ,GETBUYERDEPTNAME(FIN.GATE_CD, MAX(FIN.PR_BUYER_CD), MAX(FIN.PR_DEPT_CD), #{ses.langCd}) AS PR_BUYER_NM ,FIN.BID_NUM ,FIN.BID_CNT ,MAX(FIN.ANN_NO) AS ANN_NO ,MAX(FIN.ANN_DATE) AS ANN_DATE ,MAX(FIN.ANN_ITEM) AS ANN_ITEM ,MAX(FIN.CONT_TYPE1) AS CONT_TYPE1 ,GETCOMCODE(FIN.GATE_CD, 'M301', MAX(FIN.CONT_TYPE1), 0, #{ses.langCd}) AS CONT_TYPE1_NM ,MAX(FIN.CONT_TYPE2) AS CONT_TYPE2 ,GETCOMCODE(FIN.GATE_CD, 'M302', MAX(FIN.CONT_TYPE2), 0, #{ses.langCd}) AS CONT_TYPE2_NM ,MAX(FIN.PURCHASE_TYPE) AS PURCHASE_TYPE ,GETCODENAME(FIN.GATE_CD, 'M061', MAX(FIN.PURCHASE_TYPE), #{ses.langCd}) AS PURCHASE_TYPE_NM ,GETCODENAME(FIN.GATE_CD, 'M044', MAX(FIN.TCO_FLAG), #{ses.langCd}) AS TCO_FLAG ,(TO_CHAR(GETDECPERSONALINFO(MAX(FIN.TECH_SCORE))), '-') AS TECH_SCORE ,(TO_CHAR(MAX(FIN.PRC_SCORE)), '-') AS PRC_SCORE ,FIN.VENDOR_CD ,GETCOMPANYNAME(FIN.GATE_CD, FIN.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM ,GETDECPERSONALINFO(FIN.VENDOR_PIC_USER_NM) AS VENDOR_PIC_USER_NM ,GETDECPERSONALINFO(FIN.VENDOR_PIC_USER_CELL_NUM) AS VENDOR_PIC_USER_CELL_NUM ,GETDECPERSONALINFO(FIN.VENDOR_PIC_USER_EMAIL) AS VENDOR_PIC_USER_EMAIL ,MAX(FIN.BID_STATUS) AS BID_STATUS ,GETCODENAME(FIN.GATE_CD, 'M343', MAX(FIN.BID_STATUS), #{ses.langCd}) AS BID_STATUS_NM ,LISTAGG(CASE WHEN FIN.RNUM_VOTE_CNT = 1 THEN FIN.VOTE_CNT'차:('TO_CHAR((FIN.BID_AMT,0), 'FM999,999,999,999,999')')' END,' ,') WITHIN GROUP (ORDER BY FIN.VOTE_CNT) AS VOTECNT ,(SUM(CASE WHEN FIN.RNUM_PR_CNT = 1 THEN FIN.PR_AMT END),0) AS PR_AMT ,(SUM(CASE WHEN FIN.RNUM_BID_CNT = 1 THEN FIN.FINAL_ESTM_PRC END),0) AS FINAL_ESTM_PRC ,(SUM(CASE WHEN FIN.RNUM_CONT_CNT = 1 AND FIN.CONT_CNT = 1 THEN FIN.CONT_AMT END),0) AS CONT_AMT ,LISTAGG(CASE WHEN FIN.RNUM_CONT_CNT = 1 THEN FIN.CONT_NUM_CNT END,' | ') WITHIN GROUP (ORDER BY FIN.CONT_NUM_CNT) AS CONT_NUM_CNT FROM ( SELECT BDDT.GATE_CD ,BDDT.BUYER_CD ,BDDT.BID_NUM ,BDDT.BID_CNT ,BDVO.VENDOR_CD ,BDVO.VOTE_CNT ,(BDVO.BID_AMT,0)+(BDVO.TCO_AMT,0) AS BID_AMT ,BDHD.ANN_NO ,BDHD.ANN_DATE ,BDHD.ANN_ITEM ,BDHD.CONT_TYPE1 ,BDHD.CONT_TYPE2 ,BDDT.PURCHASE_TYPE ,BDHD.TCO_FLAG ,BDSP.TECH_SCORE ,BDSP.PRC_SCORE ,BDAP.VENDOR_PIC_USER_NM ,BDAP.VENDOR_PIC_USER_CELL_NUM ,BDAP.VENDOR_PIC_USER_EMAIL ,BDVO.BID_STATUS ,CASE WHEN ECMT.CONT_NUM IS NOT NULL THEN ECMT.CONT_NUM'-'ECMT.CONT_CNT'/('TO_CHAR(ECCT.CONT_DATE,'YYYY-MM-DD')')/('TO_CHAR((ECCT.CONT_AMT,0), 'FM999,999,999,999,999')')' ELSE '' END AS CONT_NUM_CNT ,(ECMT.CONT_CNT,0) AS CONT_CNT ,ECCT.CONT_DATE ,ECCT.CONT_AMT ,PRDT.PR_AMT ,BDES.FINAL_ESTM_PRC ,PRDT.PR_BUYER_CD ,PRDT.PR_DEPT_CD ,CASE WHEN ECMT.CONT_NUM IS NOT NULL THEN ROW_NUMBER() OVER (PARTITION BY BDVO.VENDOR_CD,ECMT.CONT_NUM,ECMT.CONT_CNT ORDER BY BDVO.VENDOR_CD,ECMT.CONT_NUM,ECMT.CONT_CNT DESC) ELSE 0 END AS RNUM_CONT_CNT ,ROW_NUMBER() OVER (PARTITION BY BDVO.VENDOR_CD,BDVO.BID_NUM,BDVO.BID_CNT,BDVO.VOTE_CNT ORDER BY BDVO.VENDOR_CD,BDVO.BID_NUM,BDVO.BID_CNT,BDVO.VOTE_CNT DESC) AS RNUM_VOTE_CNT ,ROW_NUMBER() OVER (PARTITION BY BDVO.VENDOR_CD,BDVO.BID_NUM,BDVO.BID_CNT,PRDT.PR_NUM,PRDT.PR_SQ ORDER BY BDVO.VENDOR_CD,PRDT.PR_NUM,PRDT.PR_SQ DESC) AS RNUM_PR_CNT ,ROW_NUMBER() OVER (PARTITION BY BDVO.VENDOR_CD,BDDT.BID_NUM,BDDT.BID_CNT ORDER BY BDVO.VENDOR_CD,BDDT.BID_NUM,BDDT.BID_CNT DESC) AS RNUM_BID_CNT FROM STOCBDDT BDDT JOIN STOCBDHD BDHD ON (BDDT.GATE_CD = BDHD.GATE_CD AND BDDT.BUYER_CD = BDHD.BUYER_CD AND BDDT.BID_NUM = BDHD.BID_NUM AND BDDT.BID_CNT = BDHD.BID_CNT AND BDHD.DEL_FLAG = '0' AND BDHD.BID_STATUS IN ('2500')) JOIN STOCBDVO BDVO ON( BDDT.GATE_CD = BDVO.GATE_CD AND BDDT.BUYER_CD = BDVO.BUYER_CD AND BDDT.BID_NUM = BDVO.BID_NUM AND BDDT.BID_CNT = BDVO.BID_CNT AND BDVO.DEL_FLAG = '0') JOIN STOCBDAP BDAP ON (BDVO.GATE_CD = BDAP.GATE_CD AND BDVO.BUYER_CD = BDAP.BUYER_CD AND BDVO.BID_NUM = BDAP.BID_NUM AND BDVO.BID_CNT = BDAP.BID_CNT AND BDVO.VENDOR_CD = BDAP.VENDOR_CD AND BDAP.DEL_FLAG = '0') LEFT JOIN STOCBDSP BDSP ON (BDAP.GATE_CD = BDSP.GATE_CD AND BDAP.BUYER_CD = BDSP.BUYER_CD AND BDAP.BID_NUM = BDSP.BID_NUM AND BDAP.BID_CNT = BDSP.BID_CNT AND BDAP.VENDOR_CD = BDSP.VENDOR_CD AND BDSP.DEL_FLAG = '0') JOIN STOCPRDT PRDT ON( BDDT.GATE_CD = PRDT.GATE_CD AND BDDT.PR_NUM = PRDT.PR_NUM AND BDDT.PR_SQ = PRDT.PR_SQ AND PRDT.DEL_FLAG = '0') LEFT JOIN STOCECMT ECMT JOIN STOCECCT ECCT ON( ECMT.GATE_CD = ECCT.GATE_CD AND ECMT.BUYER_CD = ECCT.BUYER_CD AND ECMT.CONT_NUM = ECCT.CONT_NUM AND ECMT.CONT_CNT = ECCT.CONT_CNT AND ECMT.DEL_FLAG = '0' AND ECCT.DEL_FLAG = '0') ON( BDDT.GATE_CD = ECMT.GATE_CD AND BDDT.BUYER_CD = ECMT.BUYER_CD AND BDDT.PR_NUM = ECMT.PR_NUM AND BDDT.PR_SQ = ECMT.PR_SQ) LEFT JOIN STOCBDES BDES ON( BDDT.GATE_CD = BDES.GATE_CD AND BDDT.BUYER_CD = BDES.BUYER_CD AND BDDT.BID_NUM = BDES.BID_NUM AND BDES.BID_CNT = '1' AND BDES.DEL_FLAG = '0') WHERE BDDT.BUYER_CD = #{ses.companyCd} AND BDDT.DEL_FLAG = '0'
AND BDHD.ANN_DATE BETWEEN #{ANN_DATE_FROM} AND #{ANN_DATE_TO}
AND UPPER(BDHD.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(REPLACE(BDHD.ANN_ITEM, ' ', '')) LIKE '%' UPPER(REPLACE(#{ANN_ITEM}, ' ', '')) '%'
AND BDDT.BID_NUM = #{BID_NUM}
AND BDVO.VENDOR_CD = #{SETTEL_VENDOR_CD}
AND UPPER(GETCOMPANYNAME(BDVO.GATE_CD, BDVO.VENDOR_CD, #{ses.langCd})) LIKE '%' UPPER(#{SETTEL_VENDOR_NM}) '%'
AND BDHD.CONT_TYPE1 = #{CONT_TYPE1}
) FIN GROUP BY FIN.GATE_CD,FIN.BUYER_CD,FIN.BID_NUM,FIN.BID_CNT,FIN.VENDOR_CD,FIN.VENDOR_PIC_USER_NM, FIN.VENDOR_PIC_USER_CELL_NUM, FIN.VENDOR_PIC_USER_EMAIL ORDER BY FIN.BID_NUM DESC,FIN.BID_CNT DESC, (CASE WHEN MIN(FIN.BID_STATUS) = '300' THEN 1 ELSE 0 END) DESC
